}

function groupHeader(g: GrepGroup): string {
  if (g.symbol) return `${g.symbol.name} · ${g.symbol.kind} · ${g.symbol.path}:${g.symbol.span} · ${g.inDegree} in-edges`;
  return `${g.path} (module level) · ${g.inDegree} in-edges`;
}

